firmware_template.source:
#include "rs485.h"
#include <HardwareSerial.h>
#define DE_PIN 4
static HardwareSerial rs(1);
void rs485_setup(){pinMode(DE_PIN,OUTPUT);digitalWrite(DE_PIN,LOW);rs.begin(9600,SERIAL_8N1,16,17);Serial.println("[rs485] OK");}
void rs485_send(const char*d){digitalWrite(DE_PIN,HIGH);delay(1);rs.println(d);rs.flush();digitalWrite(DE_PIN,LOW);}
String rs485_receive(){String s="";while(rs.available())s+=(char)rs.read();return s;}
